1	const BASE_PREMIUMS: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	
10	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
11	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
12	const LOYALTY_DISCOUNT_RATE = 0.2;
13	const LOYALTY_YEARS_THRESHOLD = 2;
14	const CURSED_SURCHARGE_RATE = 0.5;
15	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const PROCESSING_FEE = 5;
18	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
19	const COMPONENT_BLOCK_SIZE = 3;
20	const COMPONENT_BLOCK_BASE = 60;
21	
22	const INSURANCE_VALUES: Record<string, number> = {
23	  sword: 1000,
24	  amulet: 600,
25	  staff: 800,
26	  potion: 400,
27	  rune: 250,
28	  moonstone: 250,
29	};
30	
31	const CAP_MULTIPLIER = 2;
32	const DEDUCTIBLE = 100;
33	
34	const baseForType = (type: string, count: number): number => {
35	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
36	    return COMPONENT_BLOCK_BASE;
37	  }
38	  return count * BASE_PREMIUMS[type];
39	};
40	
41	export const runScenario = (scenario: any): unknown => {
42	  const results = [];
43	  let quoteStepsSeen = 0;
44	  const policiesByStepIndex = new Map<number, { capRemaining: number; items: any[] }>();
45	  for (let stepIndex = 0; stepIndex < scenario.steps.length; stepIndex++) {
46	    const step = scenario.steps[stepIndex];
47	    if (step.op === "claim") {
48	      const policy = policiesByStepIndex.get(step.policy)!;
49	      const damage = step.incident.damages[0];
50	      const insuredItem = policy.items.find((i: any) => i.type === damage.itemType);
51	      let base = damage.amount;
52	      if (insuredItem && insuredItem.enchantment >= 8) {
53	        base = base * 0.5;
54	      } else if (insuredItem && insuredItem.material === "dragon") {
55	        base = base;
56	      }
57	      const payout = Math.max(0, base - DEDUCTIBLE);
58	      policy.capRemaining -= payout;
59	      results.push({ payout, remainingCap: policy.capRemaining });
60	      continue;
61	    }
62	    const items = step.items;
63	    const countsByType = new Map<string, number>();
64	    for (const item of items) {
65	      countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
66	    }
67	    let itemBasesSum = 0;
68	    for (const [type, count] of countsByType) {
69	      itemBasesSum += baseForType(type, count);
70	    }
71	    let itemSurcharges = 0;
72	    let insuranceSum = 0;
73	    for (const item of items) {
74	      const itemBase = BASE_PREMIUMS[item.type];
75	      if (item.cursed) {
76	        itemSurcharges += itemBase * CURSED_SURCHARGE_RATE;
77	      }
78	      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
79	        itemSurcharges += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
80	      }
81	      insuranceSum += INSURANCE_VALUES[item.type];
82	    }
83	    const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
84	      ? itemBasesSum * LOYALTY_DISCOUNT_RATE
85	      : 0;
86	    const followUpDiscount = quoteStepsSeen > 0
87	      ? itemBasesSum * FOLLOW_UP_DISCOUNT_RATE
88	      : 0;
89	    const itemsTotal = itemBasesSum + itemBasesSum * FIRST_INSURANCE_SURCHARGE_RATE - loyaltyDiscount - followUpDiscount + itemSurcharges;
90	    const premium = Math.ceil(itemsTotal + PROCESSING_FEE);
91	    results.push({ premium });
92	    policiesByStepIndex.set(stepIndex, { capRemaining: insuranceSum * CAP_MULTIPLIER, items });
93	    quoteStepsSeen++;
94	  }
95	  return { results };
96	};
